print(f"{(operacao := int(input('Insira a operação a ser executada (0 - Soma, 1 - Subtração, 2 - Multiplicação, 3 - Divisão, 4 - Média): '))) and ''}{(num1 := float(input('Insira o primeiro valor: '))) and ''}{(num2 := float(input('Insira o segundo valor: '))) and ''}{(f'O resultado da soma é {num1 + num2}.' if operacao == 0 else (f'O resultado da subtração é {num1 - num2}.' if operacao == 1 else (f'O resultado da multiplicação é {num1 * num2}.' if operacao == 2 else (f'O resultado da divisão é {num1 / num2}.' if operacao == 3 else f'O média dos números é {(num1 + num2) / 2}.' if operacao == 4 else 'Valor errado. Programa encerrado sem cálculos.'))))}")
